import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testIsQuoteCharacterSet_whenQuoteCharacterIsNotNull() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertTrue(format.isQuoteCharacterSet());
    }

    @Test
    void testIsQuoteCharacterSet_whenQuoteCharacterIsNull() throws Exception {
        // Use reflection to create CSVFormat instance with quoteCharacter = null
        java.lang.reflect.Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class, Character.class, 
                Class.forName("org.apache.commons.csv.QuoteMode"), 
                Character.class, Character.class, 
                boolean.class, boolean.class, 
                String.class, String.class, 
                Object[].class, String[].class, 
                boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);

        // QuoteMode enum instance (use DEFAULT's quoteMode)
        java.lang.reflect.Field quoteModeField = CSVFormat.class.getDeclaredField("quoteMode");
        quoteModeField.setAccessible(true);
        Object quoteMode = quoteModeField.get(CSVFormat.DEFAULT);

        CSVFormat format = constructor.newInstance(
                ',', // delimiter
                null, // quoteCharacter null
                quoteMode,
                null, // commentMarker
                null, // escapeCharacter
                false, // ignoreSurroundingSpaces
                true, // allowMissingColumnNames
                "\r\n", // recordSeparator
                null, // nullString
                null, // headerComments
                null, // header
                false, // skipHeaderRecord
                false, // allowMissingColumnNames
                false // ignoreHeaderCase
        );

        assertFalse(format.isQuoteCharacterSet());
    }
}
